insert into public.demo_events (id, event_date, headline, category, location_lat, location_lon, location_name, source_outlet, source_url, source_published_at, source_updated_at, related_event_ids, confidence_tier, magnitude) values
  ('evt_001', '2026-02-28T07:23:00.000Z', 'Iran''s supreme leader dead following major attack by U.S., Israel', 'geopolitical_conflict', 35.6892, 51.389, 'Tehran, Iran', 'AP', 'https://spectrumlocalnews.com/us/snplus/international/2026/02/28/israel-launches-attack-on-iran-s-capital-with-u-s--help-as-tensions-high-over-nuclear-talks', '2026-02-28T07:23:00.000Z', '2026-03-01T02:07:00.000Z', '{evt_002}', 'direct', 2.2069969795957234),
  ('evt_002', '2026-03-02T14:30:00.000Z', 'Oil prices rise sharply after U.S.–Israeli attacks on Iran; Strait of Hormuz in focus', 'geopolitical_conflict', 26.5667, 56.25, 'Strait of Hormuz', 'Al Jazeera', 'https://www.aljazeera.com/news/2026/3/2/oil-prices-rise-sharply-after-us-israeli-attacks-on-iran', '2026-03-02T11:00:00.000Z', '2026-03-02T17:00:00.000Z', '{evt_001,evt_009}', 'direct', 2.2069969795957234),
  ('evt_003', '2026-03-27T13:30:00.000Z', 'Broad tech selloff as Iran-driven oil spike revives inflation and rate fears', 'macro_policy', 40.7069, -74.0113, 'New York (NYSE)', 'Market wrap', '', '2026-03-27T13:30:00.000Z', '2026-03-27T20:00:00.000Z', '{evt_002}', 'indirect', 3.9510442389467335),
  ('evt_004', '2026-04-01T14:00:00.000Z', 'Peace-talk reports trigger de-escalation; oil reverses, XOM -5% intraday', 'geopolitical_conflict', 46.2044, 6.1432, 'Geneva (talks)', 'Wire reports', '', '2026-04-01T14:00:00.000Z', null, '{evt_002,evt_005}', 'direct', 5.234000171600665),
  ('evt_005', '2026-04-08T18:00:00.000Z', 'Trump announces two-week pause; oil drops, Delta surges', 'macro_policy', 38.8977, -77.0365, 'Washington, D.C.', 'Wire reports', '', '2026-04-08T18:00:00.000Z', null, '{evt_004}', 'direct', 4.691600432917278),
  ('evt_006', '2026-04-23T20:05:00.000Z', 'Tesla falls 3.4% despite earnings beat — capex guidance, not oil, is the driver', 'earnings', 30.2226, -97.618, 'Austin, TX (Tesla HQ)', 'Company report', '', '2026-04-23T20:05:00.000Z', null, '{evt_003}', 'direct', 3.5586199575237787),
  ('evt_007', '2026-06-15T12:00:00.000Z', 'Framework to end the war confirmed; Brent -4.5%, XOM gives back gains', 'geopolitical_conflict', 46.2044, 6.1432, 'Geneva (talks)', 'Wire reports', '', '2026-06-15T12:00:00.000Z', null, '{evt_002}', 'direct', 4.142572998740872),
