insert into public.demo_event_impacts (event_id, ticker, tier, direction, reasoning, pct_change, price, reaction_date) values
  ('evt_001', 'XOM', 'direct', 'up', 'Strikes on a major oil-producing nation raise the risk of supply disruption near the Gulf. Crude prices climb, which flows straight into ExxonMobil upstream revenue and refining margins — a mechanical, business-level link.', 1.127869652920082, 154.22000122070312, '2026-03-02'),
  ('evt_001', 'DAL', 'direct', 'down', 'Higher crude feeds directly into jet-fuel prices, Delta''s single largest variable cost. Fuel-cost exposure is a direct P&L hit, so the stock sells off on the supply-shock headline.', -2.2069969795957234, 64.25, '2026-03-02'),
  ('evt_002', 'XOM', 'direct', 'up', '~20% of seaborne oil transits the Strait of Hormuz. Disruption fear spikes crude; XOM traded up ~4% pre-market as an integrated-oil beneficiary of higher prices.', 1.127869652920082, 154.22000122070312, '2026-03-02'),
  ('evt_002', 'DAL', 'direct', 'down', 'Same Hormuz shock, opposite sign: a crude spike raises Delta’s projected jet-fuel bill, so shares fell 5%+ pre-market on margin-compression fears.', -2.2069969795957234, 64.25, '2026-03-02'),
  ('evt_003', 'MSFT', 'indirect', 'down', 'Causal chain: oil spike → higher headline inflation expectations → market fears the Fed holds rates “higher for longer” → a higher discount rate compresses the valuation of long-duration megacap tech. MSFT was the week’s largest tech mover (-7%). No direct business link to oil — the transmission is purely macro/sentiment, hence indirect.', -2.5138705840217375, 356.7699890136719, '2026-03-27'),
  ('evt_003', 'NVDA', 'indirect', 'down', 'Same rate-fear mechanism as MSFT: high-multiple AI hardware name de-rates when discount rates are expected to rise. -3% on the day with no oil-specific business exposure.', -2.17239027176487, 167.52000427246094, '2026-03-27'),
  ('evt_003', 'AMZN', 'indirect', 'down', 'Rate-driven multiple compression on a long-duration growth name (-3%). Secondary nuance: higher fuel could raise fulfillment costs, but the day’s move was macro-sentiment, not that direct link.', -3.9510442389467335, 199.33999633789062, '2026-03-27'),
  ('evt_003', 'TSLA', 'indirect', 'down', 'Caught in the broad rate-fear selloff (-2%) rather than any oil-specific driver — indirect, sentiment-led.', -2.762623735986156, 361.8299865722656, '2026-03-27'),
  ('evt_003', 'AAPL', 'unrelated', 'none', 'The control case: Apple actually posted a slight GAIN the same week while its megacap peers fell. The selloff’s rate-driven mechanism didn’t transmit to AAPL that day, so linking it to the oil headline would be false pattern-matching — flagged unrelated.', -1.6173025219509891, 248.8000030517578, '2026-03-27'),
  ('evt_004', 'XOM', 'direct', 'down', 'De-escalation headlines unwind the supply-risk premium in crude. Falling oil directly reverses the earlier XOM trade — down ~5% intraday.', -5.234000171600665, 160.77999877929688, '2026-04-01'),
  ('evt_004', 'DAL', 'direct', 'up', 'Lower crude lowers projected jet-fuel costs, directly improving Delta’s margin outlook — the mirror image of the spike trade.', 1.6847097783286875, 67.5999984741211, '2026-04-01'),
  ('evt_005', 'DAL', 'direct', 'up', 'A pause lowers near-term supply risk; the resulting oil-price drop directly cuts Delta’s largest cost input, and shares surged on the improved fuel-cost outlook.', 3.7488555036684925, 68.08000183105469, '2026-04-08'),
  ('evt_005', 'XOM', 'direct', 'down', 'Falling crude on de-escalation directly pressures integrated-oil revenue and the stock.', -4.691600432917278, 156.22000122070312, '2026-04-08'),
  ('evt_006', 'TSLA', 'direct', 'down', 'The best “same day, two causes” teaching case. Tesla BEAT EPS estimates, yet fell 3.4%. The real, company-specific driver was raised capex guidance for robots/factories, which pressures free-cash-flow expectations. Oil-driven market pressure also hit the tape that day, but attributing TSLA’s drop to oil would be wrong — the direct cause is the capex guidance in its own earnings release.', -3.5586199575237787, 373.7200012207031, '2026-04-23'),
  ('evt_007', 'XOM', 'direct', 'down', 'A confirmed peace framework removes the war-risk premium from oil. Brent fell 4.5% and XOM gave back its conflict-driven gains — a direct price-to-revenue link.', -4.142572998740872, 140.9199981689453, '2026-06-15'),
  ('evt_007', 'DAL', 'direct', 'up', 'Lower crude directly reduces Delta’s fuel-cost outlook, supporting the shares.', 1.2159910497444621, 84.06999969482422, '2026-06-15'),
  ('evt_008', 'XOM', 'indirect', 'down', 'The reasoning-stress-test: a fresh attack headline “should” push oil up, but Brent FELL. The market weighted ample spare capacity and soft demand over the incident, so the naive “conflict → oil up → XOM up” link did NOT hold. Flagged indirect / low-confidence precisely because the mechanical link broke down.', -0.7342855276018787, 136.5399932861328, '2026-06-26'),
  ('evt_008', 'DAL', 'indirect', 'up', 'With crude falling despite the attack, Delta’s fuel outlook improved — but the low-confidence, counterintuitive setup makes this indirect rather than a clean direct read.', 0.4994018905922799, 92.56999969482422, '2026-06-26'),
  ('evt_009', 'XOM', 'direct', 'up', 'A tanker attack plus a revoked oil-sale license tightens supply expectations. Brent rose 3% (5.6% after-hours), directly lifting XOM as a higher-price beneficiary. Same causal shape as the Mar 2 Hormuz event — hence the event-to-event link.', 3.847845137832357, 141.69000244140625, '2026-07-07'),
  ('evt_009', 'DAL', 'direct', 'down', 'Renewed crude spike raised jet-fuel cost fears; Delta fell 2.93% to $86.02 — a direct fuel-cost reaction.', -3.326792148347784, 88.62999725341797, '2026-07-07'),
  ('evt_010', 'NVDA', 'unrelated', 'down', 'The key control case. Nvidia fell 1.5–2.2% on the SAME day as the tanker-attack oil headline, so a naive “blame the biggest headline” model would tie it to Iran. The real driver was a competitive-threat report that DeepSeek is building custom chips — unrelated to the geopolitical oil move. Correctly attributing this proves the system reasons about causation instead of matching same-day headlines.', 0.7056965494693367, 196.92999267578125, '2026-07-07');
